// No active A/B tests to evaluate
return [{ json: {
  status: 'no_active_tests',
  timestamp: new Date().toISOString()
} }];

// Flatten active tests into individual items for processing
const tests = $('Fetch Active SMS/Email Tests').first().json.body;
return tests.map(t => ({ json: t }));

// Calculate winner eligibility for this A/B test
const sends = $('Get Variant Send Counts').first().json.body;
const test = $('Split Tests').first().json;
const minSends = test.min_sends_per_variant || 30;

// Group sends by variant_id
const grouped = {};
for (const s of sends) {
  if (!grouped[s.variant_id]) grouped[s.variant_id] = { total: 0, converted: 0 };
  grouped[s.variant_id].total++;
  if (s.converted) grouped[s.variant_id].converted++;
}

const variants = Object.entries(grouped);

// Need at least 2 variants to compare
if (variants.length < 2) {
  return [{ json: {
    eligible: false,
    reason: 'less_than_2_variants',
    test_id: test.id,
    test_name: test.name || test.id
  } }];
}

// Check minimum sends per variant
const [v1, v2] = variants;
if (v1[1].total < minSends || v2[1].total < minSends) {
  return [{ json: {
    eligible: false,
    reason: 'insufficient_sends',
    test_id: test.id,
    test_name: test.name || test.id,
    v1_id: v1[0],
    v1_sends: v1[1].total,
    v2_id: v2[0],
    v2_sends: v2[1].total,
    min_required: minSends
  } }];
}

// Calculate conversion rates
const rate1 = v1[1].converted / v1[1].total;
const rate2 = v2[1].converted / v2[1].total;

// Check for >20% relative improvement
const maxRate = Math.max(rate1, rate2, 0.001);
const relativeImprovement = Math.abs(rate1 - rate2) / maxRate;

if (relativeImprovement > 0.20) {
  const winnerId = rate1 > rate2 ? v1[0] : v2[0];
  const winnerRate = rate1 > rate2 ? rate1 : rate2;
  const loserRate = rate1 > rate2 ? rate2 : rate1;
  return [{ json: {
    eligible: true,
    test_id: test.id,
    test_name: test.name || test.id,
    winner_variant_id: winnerId,
    winner_rate: Math.round(winnerRate * 10000) / 100,
    loser_rate: Math.round(loserRate * 10000) / 100,
    relative_improvement: Math.round(relativeImprovement * 10000) / 100,
    v1_id: v1[0],
    v1_sends: v1[1].total,
    v1_converted: v1[1].converted,
    v1_rate: Math.round(rate1 * 10000) / 100,
    v2_id: v2[0],
    v2_sends: v2[1].total,
    v2_converted: v2[1].converted,
    v2_rate: Math.round(rate2 * 10000) / 100,
    start_date: test.start_date || test.created_at
  } }];
}

return [{ json: {
  eligible: false,
  reason: 'no_significant_difference',
  test_id: test.id,
  test_name: test.name || test.id,
  rate1: Math.round(rate1 * 10000) / 100,
  rate2: Math.round(rate2 * 10000) / 100,
  relative_improvement: Math.round(relativeImprovement * 10000) / 100,
  threshold: 20
} }];

